from flask import Flask, request, jsonify, Response
from flask_cors import CORS
import requests, os, json, sqlite3, threading

app = Flask(__name__)
CORS(app, origins="*")

CLAUDE_API_KEY = os.environ.get("CLAUDE_API_KEY", "")
WA_TOKEN      = os.environ.get("WA_TOKEN", "")
WA_PHONE_ID   = os.environ.get("WA_PHONE_ID", "")
VERIFY_TOKEN  = os.environ.get("VERIFY_TOKEN", "mykonos2024")

CONVERSATIONS = {}
db_lock = threading.Lock()

# ─── DATABASE ────────────────────────────────────────────────
def get_db():
    conn = sqlite3.connect("/tmp/mykonos.db")
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    with get_db() as conn:
        conn.execute("""CREATE TABLE IF NOT EXISTS bookings (
            id INTEGER PRIMARY KEY,
            data TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )""")
        conn.commit()

init_db()

def load_bookings():
    with db_lock:
        with get_db() as conn:
            rows = conn.execute("SELECT data FROM bookings ORDER BY created_at ASC").fetchall()
            return [json.loads(r["data"]) for r in rows]

def save_booking(b):
    with db_lock:
        with get_db() as conn:
            existing = conn.execute("SELECT id FROM bookings WHERE id=?", (b["id"],)).fetchone()
            if existing:
                conn.execute("UPDATE bookings SET data=? WHERE id=?", (json.dumps(b), b["id"]))
            else:
                conn.execute("INSERT INTO bookings (id, data) VALUES (?,?)", (b["id"], json.dumps(b)))
            conn.commit()

def delete_booking(bid):
    with db_lock:
        with get_db() as conn:
            conn.execute("DELETE FROM bookings WHERE id=?", (bid,))
            conn.commit()

def replace_all_bookings(bookings_list):
    with db_lock:
        with get_db() as conn:
            conn.execute("DELETE FROM bookings")
            for b in bookings_list:
                conn.execute("INSERT INTO bookings (id, data) VALUES (?,?)", (b["id"], json.dumps(b)))
            conn.commit()

# ─── WHATSAPP ────────────────────────────────────────────────
def send_wa_message(to, text):
    if not WA_TOKEN or not WA_PHONE_ID:
        return
    requests.post(
        f"https://graph.facebook.com/v19.0/{WA_PHONE_ID}/messages",
        headers={"Authorization": f"Bearer {WA_TOKEN}", "Content-Type": "application/json"},
        json={"messaging_product": "whatsapp", "to": to, "type": "text", "text": {"body": text}},
        timeout=10
    )

SYSTEM_PROMPT = """You are the booking assistant for Mykonos Sailing, a premier yacht charter company in Mykonos, Greece.

You ONLY help customers with bookings and questions about cruises.
NEVER discuss internal business data, revenue, or operational information.

COMPANY: Mykonos Sailing | mykonossailing.gr | @mykonossailing
DEPARTURE: Ornos Bay, small dock on left side of beach

CRUISES:
1. 5hr South Coast Cruise (10-3pm or 3:30-8:30pm) - Private or Semi-Private
2. 5hr Delos & Rhenia (10-3pm or 3:30-8:30pm) - Private or Semi-Private
3. 3hr Sunset Cruise (5:30pm-sunset)
4. 8hr Full Day: Delos, Rhenia & South Coast (10-6pm)
5. 8hr Full Day South Coast (10-6pm)
6. 3-Day Charter: Mykonos-Paros-Naxos
7. 3-Day Charter: Mykonos-Syros-Antiparos
8. Multi-Day Tailor Made

ALL CRUISES INCLUDE: Meals, unlimited drinks, beach towels, snorkeling/SUP, music, professional crew.
PRICING: Never give specific prices. Say pricing depends on vessel and group size.

BOOKING INFO TO COLLECT: name, email, cruise type, private/semi-private, date, number of guests.

Reply in the SAME language as the customer. Keep replies concise for WhatsApp.
When all booking info collected, end with:
BOOKING_DATA:{"name":"...","email":"...","cruise":"...","date":"...","guests":"...","slot":"...","notes":"..."}"""

@app.route("/webhook", methods=["GET"])
def verify():
    mode      = request.args.get("hub.mode")
    token     = request.args.get("hub.verify_token")
    challenge = request.args.get("hub.challenge")
    if mode == "subscribe" and token == VERIFY_TOKEN:
        return challenge, 200
    return "Forbidden", 403

@app.route("/webhook", methods=["POST"])
def receive_message():
    try:
        data    = request.get_json()
        entry   = data.get("entry", [{}])[0]
        changes = entry.get("changes", [{}])[0]
        value   = changes.get("value", {})
        msgs    = value.get("messages", [])

        for msg in msgs:
            wa_id = msg.get("from")
            if msg.get("type") == "text":
                user_text = msg["text"]["body"]
                if wa_id not in CONVERSATIONS:
                    CONVERSATIONS[wa_id] = []
                CONVERSATIONS[wa_id].append({"role": "user", "content": user_text})
                if len(CONVERSATIONS[wa_id]) > 20:
                    CONVERSATIONS[wa_id] = CONVERSATIONS[wa_id][-20:]

                r = requests.post(
                    "https://api.anthropic.com/v1/messages",
                    headers={"x-api-key": CLAUDE_API_KEY, "anthropic-version": "2023-06-01", "content-type": "application/json"},
                    json={"model": "claude-sonnet-4-6", "max_tokens": 1024, "system": SYSTEM_PROMPT, "messages": CONVERSATIONS[wa_id]},
                    timeout=30
                )
                reply = r.json().get("content", [{}])[0].get("text", "")
                if reply:
                    CONVERSATIONS[wa_id].append({"role": "assistant", "content": reply})
                    clean = reply[:reply.find("BOOKING_DATA:")].strip() if "BOOKING_DATA:" in reply else reply
                    send_wa_message(wa_id, clean)
                    # Save booking to DB
                    if "BOOKING_DATA:" in reply:
                        try:
                            idx = reply.find("BOOKING_DATA:") + len("BOOKING_DATA:")
                            raw = reply[idx:].strip()
                            end_idx = raw.find("}") + 1
                            d = json.loads(raw[:end_idx])
                            import time
                            bid = int(time.time() * 1000)
                            b = {
                                "id": bid,
                                "name": d.get("name", d.get("guest_name", "Guest")),
                                "email": d.get("email", ""),
                                "phone": d.get("phone", ""),
                                "cruise": d.get("cruise", d.get("itinerary", "")),
                                "slot": d.get("slot", d.get("time", "")),
                                "date": d.get("date", ""),
                                "guests": d.get("guests", d.get("num_guests", "")),
                                "price": d.get("price", ""),
                                "notes": d.get("notes", ""),
                                "status": "new",
                                "fromChat": True,
                                "createdAt": __import__("datetime").datetime.utcnow().isoformat()
                            }
                            save_booking(b)
                        except Exception as ex:
                            print(f"Booking parse error: {ex}")
    except Exception as e:
        print(f"Error: {e}")
    return jsonify({"status": "ok"}), 200

@app.route("/bookings", methods=["GET"])
def get_bookings():
    return jsonify({"bookings": load_bookings()})

@app.route("/bookings", methods=["POST"])
def set_bookings():
    data = request.get_json()
    if data and "bookings" in data:
        replace_all_bookings(data["bookings"])
    return jsonify({"ok": True})

@app.route("/booking/<int:bid>", methods=["DELETE"])
def del_booking(bid):
    delete_booking(bid)
    return jsonify({"ok": True})

@app.route("/booking/<int:bid>", methods=["PUT"])
def update_booking(bid):
    b = request.get_json()
    if b:
        b["id"] = bid
        save_booking(b)
    return jsonify({"ok": True})

DASHBOARD_B64 = ""

@app.route("/", methods=["GET"])
def home():
    import base64 as b64
    return Response(b64.b64decode(DASHBOARD_B64).decode("utf-8"), mimetype="text/html")

@app.route("/chat", methods=["POST"])
def chat():
    try:
        data = request.get_json()
        r = requests.post(
            "https://api.anthropic.com/v1/messages",
            headers={"x-api-key": CLAUDE_API_KEY, "anthropic-version": "2023-06-01", "content-type": "application/json"},
            json={"model": "claude-sonnet-4-6", "max_tokens": 1024, "system": data.get("system",""), "messages": data.get("messages",[])},
            timeout=30
        )
        return jsonify(r.json()), r.status_code
    except Exception as e:
        return jsonify({"error": {"message": str(e)}}), 500

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 8080)))
